namespace sv_3d74d773d26f40469b7e53f892341062.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single user circuit.
/// Components subscribe to <see cref="OnChanged"/> to react when the selection changes.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-001", "Warehouse A — East"),
        ("WH-002", "Warehouse B — West"),
        ("WH-003", "Warehouse C — North"),
    ];

    private string _selectedWarehouseId = AvailableWarehouses[0].Id;

    public string SelectedWarehouseId => _selectedWarehouseId;

    public string SelectedWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _selectedWarehouseId).Name;

    public event Action? OnChanged;

    public void SetWarehouse(string warehouseId)
    {
        if (_selectedWarehouseId == warehouseId) return;
        _selectedWarehouseId = warehouseId;
        OnChanged?.Invoke();
    }
}

namespace sv_3d74d773d26f40469b7e53f892341062.Services;

/// <summary>
/// Simulates a database query for low-stock item counts.
/// Registered as singleton — it has no per-user state.
/// </summary>
public sealed class InventoryAlertService
{
    private static readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database round-trip
        int count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

namespace sv_3d74d773d26f40469b7e53f892341062.Services;

/// <summary>
/// Scoped service that broadcasts alert-count updates to all subscribed components
/// within the same user circuit. Any component can trigger an update; every subscriber
/// is notified — this solves cross-component communication for non-parent-child trees.
/// </summary>
public sealed class AlertNotificationService
{
    private readonly InventoryAlertService _alertService;

    public AlertNotificationService(InventoryAlertService alertService)
    {
        _alertService = alertService;
    }

    public int CurrentLowStockCount { get; private set; }

    /// <summary>
    /// Fired after <see cref="CurrentLowStockCount"/> is refreshed.
    /// Subscribers should call <c>InvokeAsync(StateHasChanged)</c> in their handler.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    /// <summary>
    /// Fetches the latest low-stock count for the given warehouse and notifies all subscribers.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        CurrentLowStockCount = await _alertService.GetLowStockCountAsync(warehouseId);
        if (OnAlertCountChanged is not null)
        {
            await OnAlertCountChanged.Invoke();
        }
    }
}

