namespace sv_3d74d773d26f40469b7e53f892341062.Services;

/// <summary>
/// Scoped service that broadcasts alert-count updates to all subscribed components
/// within the same user circuit. Any component can trigger an update; every subscriber
/// is notified — this solves cross-component communication for non-parent-child trees.
/// </summary>
public sealed class AlertNotificationService
{
    private readonly InventoryAlertService _alertService;

    public AlertNotificationService(InventoryAlertService alertService)
    {
        _alertService = alertService;
    }

    public int CurrentLowStockCount { get; private set; }

    /// <summary>
    /// Fired after <see cref="CurrentLowStockCount"/> is refreshed.
    /// Subscribers should call <c>InvokeAsync(StateHasChanged)</c> in their handler.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    /// <summary>
    /// Fetches the latest low-stock count for the given warehouse and notifies all subscribers.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        CurrentLowStockCount = await _alertService.GetLowStockCountAsync(warehouseId);
        if (OnAlertCountChanged is not null)
        {
            await OnAlertCountChanged.Invoke();
        }
    }
}

