@using sv_3d74d773d26f40469b7e53f892341062.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label class="warehouse-label" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            value="@WarehouseState.SelectedWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChanged += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChanged -= StateHasChanged;
    }
}

.warehouse-selector {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.warehouse-label {
    white-space: nowrap;
    font-weight: 500;
}

.warehouse-selector .form-select {
    width: auto;
    min-width: 200px;
}

@using sv_3d74d773d26f40469b7e53f892341062.Services
@inject AlertNotificationService AlertNotification
@implements IDisposable

@if (AlertNotification.CurrentLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill alert-badge">@AlertNotification.CurrentLowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill alert-badge">0</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertNotification.OnAlertCountChanged += OnCountChanged;
    }

    private async Task OnCountChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertNotification.OnAlertCountChanged -= OnCountChanged;
    }
}

