﻿@page "/"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject AlertNotificationService AlertNotification
@implements IAsyncDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Currently viewing: <strong>@WarehouseState.SelectedWarehouseName</strong></p>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="card-text display-6">
                    <AlertBadge />
                    <span class="ms-2 fs-5">items below minimum level</span>
                </p>
                <p class="text-muted mb-0">
                    <small>Auto-refreshes every 10 seconds</small>
                </p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Warehouse ID</h5>
                <p class="card-text display-6">@WarehouseState.SelectedWarehouseId</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Status</h5>
                <p class="card-text display-6">
                    @if (_isPolling)
                    {
                        <span class="badge bg-success">Live</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Paused</span>
                    }
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _isPolling;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChanged += OnWarehouseChanged;

        // Initial fetch then start polling
        await AlertNotification.RefreshAsync(WarehouseState.SelectedWarehouseId);
        StartPolling();
    }

    private async void OnWarehouseChanged()
    {
        // Warehouse changed — refresh immediately and restart polling
        StopPolling();
        await AlertNotification.RefreshAsync(WarehouseState.SelectedWarehouseId);
        await InvokeAsync(StateHasChanged);
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _isPolling = false;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
                await AlertNotification.RefreshAsync(WarehouseState.SelectedWarehouseId);
                await InvokeAsync(StateHasChanged);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        WarehouseState.OnChanged -= OnWarehouseChanged;
        StopPolling();
    }
}

